     1→// ============================================================================
     2→// Room Module - Service Layer
     3→// Proctoring room lifecycle management
     4→// ============================================================================
     5→
     6→import { Pool } from 'pg';
     7→
     8→// ============================================================================
     9→// Structured Error Types (Issue #8)
    10→// ============================================================================
    11→
    12→export class RoomNotFoundError extends Error {
    13→  constructor(roomCode: string) {
    14→    super(`Room not found: ${roomCode}`);
    15→    this.name = 'RoomNotFoundError';
    16→  }
    17→}
    18→
    19→export class ExamNotFoundError extends Error {
    20→  constructor(examId: number) {
    21→    super(`Exam not found: ${examId}`);
    22→    this.name = 'ExamNotFoundError';
    23→  }
    24→}
    25→
    26→export class NotEnrolledError extends Error {
    27→  constructor(teacherId: number, examId: number) {
    28→    super(`Teacher ${teacherId} is not enrolled in exam ${examId}`);
    29→    this.name = 'NotEnrolledError';
    30→  }
    31→}
    32→
    33→export class RoomCollisionError extends Error {
    34→  constructor() {
    35→    super('Failed to generate unique room code after 3 attempts');
    36→    this.name = 'RoomCollisionError';
    37→  }
    38→}
    39→
    40→export class CapacityExceededError extends Error {
    41→  constructor(enrolled: number, capacity: number) {
    42→    super(`Exam has ${enrolled} students enrolled, exceeds room capacity of ${capacity}`);
    43→    this.name = 'CapacityExceededError';
    44→  }
    45→}
    46→
    47→export class InvalidStateTransitionError extends Error {
    48→  constructor(currentStatus: string, targetStatus: string) {
    49→    super(`Invalid state transition: ${currentStatus} → ${targetStatus}`);
    50→    this.name = 'InvalidStateTransitionError';
    51→  }
    52→}
    53→
    54→export class NotRoomOwnerError extends Error {
    55→  constructor(roomId: number, teacherId: number) {
    56→    super(`Teacher ${teacherId} is not the owner of room ${roomId}`);
    57→    this.name = 'NotRoomOwnerError';
    58→  }
    59→}
    60→
    61→// ============================================================================
    62→// Type Definitions
    63→// ============================================================================
    64→
    65→export interface Room {
    66→  id: number;
    67→  exam_id: number;
    68→  teacher_id: number;
    69→  room_code: string;
    70→  status: 'created' | 'activated' | 'closed';
    71→  capacity: number;
    72→  created_at: Date;
    73→  activated_at: Date | null;
    74→  closed_at: Date | null;
    75→}
    76→
    77→export interface RoomWithExamDetails extends Room {
    78→  exam_name: string;
    79→  course_name: string;
    80→}
    81→
    82→export interface CreateRoomParams {
    83→  examId: number;
    84→  teacherId: number;
    85→}
    86→
    87→export interface ActiveRoomSummary {
    88→  id: number;
    89→  room_code: string;
    90→  exam_name: string;
    91→  student_count: number;
    92→  duration_minutes: number;
    93→  created_at: Date;
    94→}
    95→
    96→// ============================================================================
    97→// ProctoringRoomService
    98→// ============================================================================
    99→
   100→export class ProctoringRoomService {
   101→  constructor(private pg: Pool) {}
   102→
   103→  /**
   104→   * Generate a random 8-character base62 room code
   105→   * Base62: 0-9, a-z, A-Z (62 characters)
   106→   * 8 chars = 62^8 = 218 trillion combinations
   107→   */
   108→  private generateRoomCode(): string {
   109→    const chars = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';
   110→    let code = '';
   111→    for (let i = 0; i < 8; i++) {
   112→      code += chars.charAt(Math.floor(Math.random() * chars.length));
   113→    }
   114→    return code;
   115→  }
   116→
   117→  /**
   118→   * Create a new proctoring room for an exam
   119→   * Validates: exam exists, teacher enrolled, capacity not exceeded
   120→   * Generates: unique room code (retries 3x on collision)
   121→   */
   122→  async createRoom(params: CreateRoomParams): Promise<Room> {
   123→    const { examId, teacherId } = params;
   124→
   125→    // 1. Validate exam exists
   126→    const examResult = await this.pg.query(
   127→      'SELECT id, exam_name FROM exams WHERE id = $1',
   128→      [examId]
   129→    );
   130→
   131→    if (examResult.rows.length === 0) {
   132→      throw new ExamNotFoundError(examId);
   133→    }
   134→
   135→    // 2. Check teacher enrollment (Moodle course membership)
   136→    // For now, we assume teacher has access if they exist in users table
   137→    // In production, this would call MoodleService to verify enrollment
   138→    const teacherResult = await this.pg.query(
   139→      'SELECT id FROM users WHERE id = $1 AND role = $2',
   140→      [teacherId, 'teacher']
   141→    );
   142→
   143→    if (teacherResult.rows.length === 0) {
   144→      throw new NotEnrolledError(teacherId, examId);
   145→    }
   146→
   147→    // 3. Check capacity (count enrolled students for this exam)
   148→    const capacityResult = await this.pg.query<{ count: string }>(
   149→      `SELECT COUNT(DISTINCT ea.user_id) as count
   150→       FROM exam_attempts ea
   151→       WHERE ea.exam_id = $1
   152→       AND ea.status IN ('in_progress', 'submitted')`,
   153→      [examId]
   154→    );
   155→
   156→    const enrolledCount = parseInt(capacityResult.rows[0].count, 10);
   157→    const capacity = 15; // Default capacity from design
   158→
   159→    if (enrolledCount >= capacity) {
   160→      throw new CapacityExceededError(enrolledCount, capacity);
   161→    }
   162→
   163→    // 4. Generate unique room code (retry 3x on collision)
   164→    let roomCode: string = '';
   165→    let attempts = 0;
   166→    const maxAttempts = 3;
   167→
   168→    while (attempts < maxAttempts) {
   169→      roomCode = this.generateRoomCode();
   170→
   171→      // Check if code already exists
   172→      const existingResult = await this.pg.query(
   173→        'SELECT id FROM proctoring_rooms WHERE room_code = $1',
   174→        [roomCode]
   175→      );
   176→
   177→      if (existingResult.rows.length === 0) {
   178→        // Code is unique, use it
   179→        break;
   180→      }
   181→
   182→      attempts++;
   183→    }
   184→
   185→    if (attempts >= maxAttempts) {
   186→      throw new RoomCollisionError();
   187→    }
   188→
   189→    // 5. Insert room
   190→    const insertResult = await this.pg.query<Room>(
   191→      `INSERT INTO proctoring_rooms (exam_id, teacher_id, room_code, status, capacity)
   192→       VALUES ($1, $2, $3, 'created', $4)
   193→       RETURNING *`,
   194→      [examId, teacherId, roomCode, capacity]
   195→    );
   196→
   197→    return insertResult.rows[0];
   198→  }
   199→
   200→  /**
   201→   * Get room by code (for student joins)
   202→   * Includes exam details for validation
   203→   */
   204→  async getRoomByCode(roomCode: string): Promise<RoomWithExamDetails> {
   205→    const result = await this.pg.query<RoomWithExamDetails>(
   206→      `SELECT
   207→         pr.*,
   208→         e.exam_name,
   209→         e.course_name
   210→       FROM proctoring_rooms pr
   211→       JOIN exams e ON pr.exam_id = e.id
   212→       WHERE pr.room_code = $1`,
