```typescript
// POST /api/room/:code/join - Student joins with invite code
fastify.post('/api/room/:code/join', {
  schema: {
    params: { code: { type: 'string' } },
    body: {
      type: 'object',
      properties: {
        studentName: { type: 'string' },
