```javascript
const API_BASE_URL = 'http://localhost:5000';

document.getElementById('joinForm').addEventListener('submit', async (e) => {
  e.preventDefault();

  const inviteCode = document.getElementById('inviteCode').value.trim().toUpperCase();
  const studentName = document.getElementById('studentName').value.trim();
  const studentEmail = document.getElementById('studentEmail').value.trim();
  const joinButton = document.getElementById('joinButton');
  const errorMessage = document.getElementById('errorMessage');

  // Reset state
  joinButton.disabled = true;
  joinButton.textContent = 'Joining...';
  errorMessage.hidden = true;

  try {
    const response = await fetch(`${API_BASE_URL}/api/room/${inviteCode}/join`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Manual-Proctoring-Client': '1'
      },
      body: JSON.stringify({
        studentName,
        studentEmail
      })
    });

    const data = await response.json();

    if (!response.ok || !data.success) {
      throw new Error(data.error || 'Failed to join room');
    }

    // Store session
    const session = {
      token: data.data.token,
      roomId: data.data.roomId,
      attemptId: data.data.attemptId,
      examName: data.data.examName,
      courseName: data.data.courseName,
      roomCode: data.data.roomCode,
      studentName,
      studentEmail
    };

    localStorage.setItem('authSession', JSON.stringify(session));
    localStorage.setItem('token', data.data.token);

    // Redirect to exam
    window.location = 'exam.html';

  } catch (error) {
    console.error('[Join] Error:', error);
    errorMessage.textContent = error.message || 'Failed to join room. Please check your invite code and try again.';
    errorMessage.hidden = false;
    joinButton.disabled = false;
    joinButton.textContent = 'Join Room';
  }
});
```

